__attribute__((noinline))
int my_print_int(va_list args) {
  return printf("%d", va_arg(args, int));
}

__attribute__((noinline))
int my_print_string(va_list args) {
  return printf("%s", va_arg(args, const char *));
}

__attribute__((noinline))
int my_vprintf(const char *format, va_list args) {
  int i;
  int j = 0;
  for (i = 0; format[i]; ) {
    if ('%' == format[i]) {
      i += 1;
      if ('d' == format[i]) {
        j += my_print_int(args);
      } else if('s' == format[i]) {
        j += my_print_string(args);
      } else {
        putc('%', stdout);
        putc(format[i], stdout);
        j += 2;
      }
      i += 1;
    } else {
      putc(format[i], stdout);
      i += 1;
      j += 1;
